import requests

url = "https://www.fpbase.org/graphql/"

query = """
query {
  allProteins {
    edges {
      node {
        name
        slug
        seq
        primaryPdb
        exMax
        emMax
      }
    }
  }
}
"""

r = requests.post(url, json={'query': query})
if r.status_code == 200:
    data = r.json()
    edges = data.get("data", {}).get("allProteins", {}).get("edges", [])
    print(f"Found {len(edges)} proteins in FPBase")
    for edge in edges:
        p = edge["node"]
        pdb = p.get("primaryPdb")
        ex = p.get("exMax")
        em = p.get("emMax")
        # if pdb:
        #    print(f"{p['name']} ({pdb}): ex={ex}, em={em}")
        if ex == 505 or em == 610:
            print(f"MATCH: {p['name']} ({pdb}): ex={ex}, em={em}, slug={p['slug']}")
else:
    print("GraphQL failed, status:", r.status_code, r.text)
